  1→/**
  2→ * Protocol types for communication between the Rust core and TypeScript frontend.
  3→ *
  4→ * All messages are newline-delimited JSON over stdin/stdout. The core sends
  5→ * Request messages and receives Response messages back. Every message includes
  6→ * a protocol version for compatibility checking.
  7→ */
  8→
  9→export const PROTOCOL_VERSION = "0.1.0";
 10→export const FRONTEND_LANGUAGE = "typescript";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Request: Core → Frontend
 14→// ---------------------------------------------------------------------------
 15→
 16→export type SetupMode = "per_function" | "per_execution";
 17→
 18→export type SetupLevel = "session" | "file" | "function" | "execution";
 19→
 20→export interface SetupContextEntry {
 21→  level: SetupLevel;
 22→  context: unknown;
 23→}
 24→
 25→export interface SetupContextStack {
 26→  contexts: SetupContextEntry[];
 27→}
 28→
 29→export type GeneratorKind = "type_name" | "param_name";
 30→
 31→export type Command =
 32→  | "handshake"
 33→  | "analyze"
 34→  | "instrument"
 35→  | "execute"
 36→  | "setup"
 37→  | "teardown"
 38→  | "generate"
 39→  | "shutdown";
 40→
 41→export interface MockConfig {
 42→  symbol: string;
 43→  return_values: unknown[];
 44→  should_track_calls: boolean;
 45→  default_behavior: "return_generated" | "repeat_last" | "throw_error" | "passthrough";
 46→}
 47→
 48→interface BaseRequest {
 49→  protocol_version: string;
 50→  id: number;
 51→  command: Command;
 52→}
 53→
 54→export interface HandshakeRequest extends BaseRequest {
 55→  command: "handshake";
 56→  capabilities: string[];
 57→}
 58→
 59→export interface AnalyzeRequest extends BaseRequest {
 60→  command: "analyze";
 61→  file: string;
 62→  function?: string | null;
 63→  project_root?: string | null;
 64→}
 65→
 66→export interface InstrumentRequest extends BaseRequest {
 67→  command: "instrument";
 68→  file: string;
 69→  function: string;
 70→  mocks: MockConfig[];
 71→  project_root?: string | null;
 72→}
 73→
 74→export interface ExecuteRequest extends BaseRequest {
 75→  command: "execute";
 76→  function: string;
 77→  inputs: unknown[];
 78→  mocks: MockConfig[];
 79→  setup_context?: SetupContextStack | null;
 80→}
 81→
 82→export interface SetupRequest extends BaseRequest {
 83→  command: "setup";
 84→  file: string;
 85→  scope: string;
 86→  level: SetupLevel;
 87→  parent_context?: SetupContextStack | null;
 88→  project_root?: string | null;
 89→}
 90→
 91→export interface TeardownRequest extends BaseRequest {
 92→  command: "teardown";
 93→  scope: string;
 94→  level: SetupLevel;
 95→}
 96→
 97→export interface GenerateRequest extends BaseRequest {
 98→  command: "generate";
 99→  file: string;
100→  name: string;
101→  kind: GeneratorKind;
102→  recipe?: unknown;
103→  project_root?: string | null;
104→}
105→
106→export interface ShutdownRequest extends BaseRequest {
107→  command: "shutdown";
108→}
109→
110→export type Request =
111→  | HandshakeRequest
112→  | AnalyzeRequest
113→  | InstrumentRequest
114→  | ExecuteRequest
115→  | SetupRequest
116→  | TeardownRequest
117→  | GenerateRequest
118→  | ShutdownRequest;
119→
120→// ---------------------------------------------------------------------------
121→// Response: Frontend → Core
122→// ---------------------------------------------------------------------------
123→
124→export type ResponseStatus =
125→  | "handshake"
126→  | "analyze"
127→  | "instrument"
128→  | "execute"
129→  | "setup"
130→  | "teardown_ack"
131→  | "generate"
132→  | "shutdown_ack"
133→  | "error";
134→
135→/** Canonical error codes matching protocol/registry.yaml (11 codes). */
136→export const ALL_ERROR_CODES = [
137→  "file_not_found",
138→  "function_not_found",
139→  "parse_error",
140→  "instrumentation_failed",
141→  "execution_timeout",
142→  "execution_crash",
143→  "version_mismatch",
144→  "invalid_request",
145→  "compilation_error",
146→  "internal_error",
147→  "not_supported",
148→] as const;
149→
150→export type ErrorCode = (typeof ALL_ERROR_CODES)[number];
151→
152→interface BaseResponse {
153→  protocol_version: string;
154→  id: number;
155→  status: ResponseStatus;
156→}
157→
158→export interface HandshakeResponse extends BaseResponse {
159→  status: "handshake";
160→  frontend_version: string;
161→  language: string;
162→  capabilities: string[];
163→}
164→
165→export interface AnalyzeResponse extends BaseResponse {
166→  status: "analyze";
167→  functions: FunctionAnalysis[];
168→}
169→
170→export interface InstrumentResponse extends BaseResponse {
171→  status: "instrument";
172→  instrumented: boolean;
173→  output_file: string | null;
174→  instrumentable_line_count?: number;
175→}
176→
177→export interface ExecuteResponse extends BaseResponse {
178→  status: "execute";
179→  return_value: unknown;
180→  thrown_error: ErrorInfo | null;
181→  branch_path: BranchDecision[];
182→  lines_executed: number[];
183→  calls_to_external: ExternalCall[];
184→  path_constraints: SymConstraint[];
185→  side_effects: SideEffect[];
186→  performance: PerformanceMetrics;
187→  capture_truncation?: TruncationInfo;
188→  scope_events?: TraceEvent[];
189→  discovered_dependencies?: DiscoveredDependency[];
190→}
191→
192→export interface SetupResponse extends BaseResponse {
193→  status: "setup";
194→  setup_context: unknown;
195→}
196→
197→export interface TeardownAckResponse extends BaseResponse {
198→  status: "teardown_ack";
199→}
200→
201→export interface GenerateResponse extends BaseResponse {
202→  status: "generate";
203→  value: unknown;
204→  generator_id: string;
205→  recipe?: unknown;
206→}
207→
208→export interface ShutdownAckResponse extends BaseResponse {
209→  status: "shutdown_ack";
210→}
211→
212→export interface ErrorResponse extends BaseResponse {
213→  status: "error";
214→  code: ErrorCode;
215→  message: string;
216→  details?: unknown;
217→}
218→
219→export type Response =
220→  | HandshakeResponse
221→  | AnalyzeResponse
222→  | InstrumentResponse
223→  | ExecuteResponse
224→  | SetupResponse
225→  | TeardownAckResponse
226→  | GenerateResponse
227→  | ShutdownAckResponse
228→  | ErrorResponse;
229→
230→// ---------------------------------------------------------------------------
231→// Supporting types
232→// ---------------------------------------------------------------------------
233→
234→/** A literal constant extracted from source code for use as a candidate test input. */
235→export type LiteralValue =
236→  | { type: "int"; value: number }
237→  | { type: "float"; value: number }
238→  | { type: "str"; value: string }
239→  | { type: "bool"; value: boolean }
240→  | { type: "regex"; pattern: string };
241→
242→export interface CryptoBoundary {
243→  symbol: string;
244→  source_module: string;
245→  direction: "encrypt" | "decrypt" | "both";
246→  output: "ciphertext" | "plaintext" | "key" | "hash" | "signature" | "verified";
247→  param_roles: Record<string, "key" | "data" | "iv" | "nonce" | "tag" | "aad" | "algorithm">;
248→  call_sites: number[];
249→}
250→
251→export interface FunctionAnalysis {
252→  name: string;
253→  exported?: boolean;
254→  params: ParamInfo[];
255→  branches: BranchInfo[];
256→  dependencies: ExternalDependency[];
257→  return_type: TypeInfo;
258→  start_line: number;
259→  end_line: number;
260→  literals?: LiteralValue[];
261→  crypto_boundaries?: CryptoBoundary[];
262→}
263→
264→export interface ParamInfo {
265→  name: string;
266→  type: TypeInfo;
267→  type_name?: string;
268→}
269→
270→/** Well-known complex types beyond primitives and structural types. */
271→export type ComplexKind =
272→  | "date" | "date_time" | "time" | "duration"
273→  | "reg_exp" | "char" | "symbol"
274→  | "big_int" | "big_decimal" | "complex" | "rational" | "range"
275→  | "buffer" | "bit_set"
276→  | "error" | "option" | "result"
277→  | "closure" | "iterator"
278→  | "url" | "ip_address"
279→  | "uuid"
280→  | "path"
281→  | "money" | "sem_ver" | "email" | "mime_type" | "color" | "geo_point" | "locale"
282→  | "rune" | "go_byte";
283→
284→export type TypeInfo =
285→  | { kind: "int" }
286→  | { kind: "float" }
287→  | { kind: "str" }
288→  | { kind: "bool" }
289→  | { kind: "unknown" }
290→  | { kind: "array"; element: TypeInfo }
291→  | { kind: "object"; fields: [string, TypeInfo][] }
292→  | { kind: "union"; variants: TypeInfo[] }
293→  | { kind: "nullable"; inner: TypeInfo }
294→  | { kind: "complex"; complex_kind: ComplexKind; metadata?: Record<string, unknown>; inner?: TypeInfo }
295→  | { kind: "opaque"; label: string };
296→
297→export interface BranchInfo {
298→  id: number;
299→  line: number;
300→  condition_text: string;
301→  condition: SymExpr | null;
302→  branch_type: BranchType;
303→}
304→
305→export type BranchType =
306→  | "if"
307→  | "else_if"
308→  | "switch"
309→  | "ternary"
310→  | "logical_and"
311→  | "logical_or"
312→  | "while"
313→  | "for";
314→
315→export type SymExpr =
316→  | { kind: "param"; name: string; path: string[] }
317→  | SymExprConst
318→  | { kind: "bin_op"; op: BinOpKind; left: SymExpr; right: SymExpr }
319→  | { kind: "un_op"; op: UnOpKind; operand: SymExpr }
320→  | { kind: "call"; name: string; receiver: SymExpr | null; args: SymExpr[] }
321→  | { kind: "unknown" };
322→
323→/** Const variant of SymExpr. Flattened to match Rust serde serialization. */
324→export type SymExprConst =
325→  | { kind: "const"; type: "int"; value: number }
326→  | { kind: "const"; type: "float"; value: number }
327→  | { kind: "const"; type: "str"; value: string }
328→  | { kind: "const"; type: "bool"; value: boolean }
329→  | { kind: "const"; type: "null" }
330→  | { kind: "const"; type: "undefined" }
331→  | { kind: "const"; type: "complex"; value: { kind: ComplexKind; repr: SymExprConst } };
332→
333→export type BinOpKind =
334→  | "eq" | "ne" | "lt" | "le" | "gt" | "ge"
335→  | "add" | "sub" | "mul" | "div" | "mod"
336→  | "and" | "or"
337→  | "bitwise_and" | "bitwise_or" | "bitwise_xor"
338→  | "in" | "instance_of";
339→
340→export type UnOpKind = "not" | "neg" | "bitwise_not" | "typeof";
341→
342→export interface BranchDecision {
343→  branch_id: number;
344→  line: number;
345→  taken: boolean;
346→  constraint: SymConstraint;
347→}
348→
349→export type ScopeEvent =
350→  | { kind: "loop_enter"; loop_id: number }
351→  | { kind: "loop_exit"; loop_id: number }
352→  | { kind: "call_enter"; call_site_id: number }
353→  | { kind: "call_exit"; call_site_id: number };
354→
355→export type TraceEvent =
356→  | { type: "branch"; decision: BranchDecision }
357→  | { type: "scope"; event: ScopeEvent };
358→
359→export type SymConstraint =
360→  | { kind: "expr"; expr: SymExpr }
361→  | { kind: "unknown"; hint: string };
362→
363→export interface ExternalCall {
364→  symbol: string;
365→  args: unknown[];
366→  return_value: unknown;
367→}
368→
369→export type DepDetectionKind = "unmocked_import" | "subprocess_spawn";
370→
371→export interface DiscoveredDependency {
372→  symbol: string;
373→  source_module: string;
374→  kind: DepDetectionKind;
375→  is_subprocess_spawn: boolean;
376→}
377→
378→export interface ExternalDependency {
379→  kind: DependencyKind;
380→  symbol: string;
381→  source_module: string;
382→  return_type: TypeInfo;
383→  param_types: TypeInfo[];
384→  call_sites: number[];
385→}
386→
387→export type DependencyKind =
388→  | "function_call"
389→  | "method_call"
390→  | "property_access"
391→  | "module_import";
392→
393→export type SideEffect =
394→  | { kind: "console_output"; level: string; message: string }
395→  | { kind: "file_write"; path: string; content: string }
396→  | { kind: "network_request"; method: string; url: string; body: unknown }
397→  | { kind: "environment_read"; variable: string; value: string | null }
398→  | { kind: "global_mutation"; name: string }
399→  | { kind: "thrown_error"; error_type: string; message: string; stack: string | null }
400→  | { kind: "global_state_change"; variable: string; before: unknown; after: unknown };
401→
402→export type ErrorCategory = "validation" | "runtime" | "infrastructure" | "unknown";
403→
404→export interface ErrorInfo {
405→  error_type: string;
406→  message: string;
407→  stack: string | null;
408→  error_category?: ErrorCategory;
409→}
410→
411→export interface TruncationInfo {
412→  was_truncated: boolean;
413→  original_lines: number;
414→  original_bytes: number;
415→}
416→
417→export interface PerformanceMetrics {
418→  wall_time_ms: number;
419→  cpu_time_us: number;
420→  heap_used_bytes: number;
421→  heap_allocated_bytes: number;
422→}
