  1→/**
  2→ * Command handlers for the Shatter protocol.
  3→ *
  4→ * Each handler receives a typed request and returns a typed response.
  5→ * The instrument handler stores instrumented source in memory so the
  6→ * execute handler can use it for branch-recording execution.
  7→ */
  8→
  9→import * as fs from "node:fs";
 10→import * as path from "node:path";
 11→import {
 12→  PROTOCOL_VERSION,
 13→  FRONTEND_LANGUAGE,
 14→  type Request,
 15→  type Response,
 16→  type ErrorResponse,
 17→  type SetupLevel,
 18→} from "./protocol.js";
 19→import { analyzeFile } from "./analyzer.js";
 20→import { instrumentFunction } from "./instrumentor.js";
 21→import {
 22→  executeFunction,
 23→  executeInstrumented,
 24→  buildExecuteResponse,
 25→  setProjectRoot,
 26→  clearModuleCache,
 27→} from "./executor.js";
 28→import {
 29→  loadSetupModule,
 30→  runSetup,
 31→  runTeardown,
 32→  loadGeneratorModule,
 33→  runGenerator,
 34→  type SetupModule,
 35→} from "./setup-loader.js";
 36→import {
 37→  loadWasmPlugin,
 38→  runWasmGenerator,
 39→  clearWasmCache,
 40→} from "./wasm-generator.js";
 41→
 42→/** Supported capabilities for this frontend. */
 43→const SUPPORTED_CAPABILITIES = [
 44→  "analyze", "execute", "instrument", "setup", "generate",
 45→  "complex_type:date", "complex_type:date_time", "complex_type:duration",
 46→  "complex_type:reg_exp", "complex_type:url", "complex_type:big_int",
 47→  "complex_type:buffer", "complex_type:error", "complex_type:symbol",
 48→];
 49→
 50→/** Track the last analyzed file so execute can resolve function references. */
 51→let lastAnalyzedFile: string | null = null;
 52→
 53→/**
 54→ * Stored instrumented sources, keyed by "file:function".
 55→ * Set by the instrument handler, consumed by the execute handler.
 56→ */
 57→const instrumentedSources = new Map<string, string>();
 58→
 59→/**
 60→ * Loaded setup modules, keyed by file path.
 61→ * Cached so teardown can use the same module instance as setup.
 62→ */
 63→const loadedSetupModules = new Map<string, SetupModule>();
 64→
 65→/**
 66→ * Setup contexts keyed by "level:scope" (e.g. "function:myFunc", "session:main").
 67→ * Separate keys per level ensure that session-, file-, function-, and
 68→ * execution-level contexts coexist without collision.
 69→ */
 70→const setupContexts = new Map<string, { module: SetupModule; context: unknown }>();
 71→
 72→/** Build a composite cache key for the setup context map. */
 73→function setupContextKey(level: SetupLevel, scope: string): string {
 74→  return `${level}:${scope}`;
 75→}
 76→
 77→/**
 78→ * Dispatch a parsed request to the appropriate handler.
 79→ *
 80→ * Returns a Response and a shutdown flag. The handler is async because
 81→ * WASM generator loading requires awaiting plugin creation.
 82→ */
 83→export async function handleRequest(request: Request): Promise<{ response: Response; shutdown: boolean }> {
 84→  if (!isVersionCompatible(request.protocol_version)) {
 85→    return {
 86→      response: errorResponse(request.id, "version_mismatch",
 87→        `Unsupported protocol version: ${request.protocol_version} (expected ${PROTOCOL_VERSION})`),
 88→      shutdown: false,
 89→    };
 90→  }
 91→
 92→  switch (request.command) {
 93→    case "handshake":
 94→      return {
 95→        response: {
 96→          protocol_version: PROTOCOL_VERSION,
 97→          id: request.id,
 98→          status: "handshake",
 99→          frontend_version: PROTOCOL_VERSION,
100→          language: FRONTEND_LANGUAGE,
101→          capabilities: SUPPORTED_CAPABILITIES,
102→        },
103→        shutdown: false,
104→      };
105→
106→    case "analyze": {
107→      if (!fs.existsSync(request.file)) {
108→        return {
109→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
110→          shutdown: false,
111→        };
112→      }
113→
114→      lastAnalyzedFile = path.resolve(request.file);
115→      setProjectRoot(request.project_root);
116→      const functions = analyzeFile(request.file, request.function, request.project_root);
117→
118→      if (request.function != null && functions.length === 0) {
119→        return {
120→          response: errorResponse(
121→            request.id,
122→            "function_not_found",
123→            `Function not found: ${request.function} in ${request.file}`,
124→          ),
125→          shutdown: false,
126→        };
127→      }
128→
129→      return {
130→        response: {
131→          protocol_version: PROTOCOL_VERSION,
132→          id: request.id,
133→          status: "analyze",
134→          functions,
135→        },
136→        shutdown: false,
137→      };
138→    }
139→
140→    case "instrument": {
141→      if (!fs.existsSync(request.file)) {
142→        return {
143→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
144→          shutdown: false,
145→        };
146→      }
147→
148→      const source = fs.readFileSync(request.file, "utf-8");
149→      const result = instrumentFunction(source, request.function, request.file, request.mocks ?? []);
150→
151→      if ("error" in result) {
152→        return {
153→          response: errorResponse(request.id, "instrumentation_failed", result.error),
154→          shutdown: false,
155→        };
156→      }
157→
158→      // Store the instrumented source for use by the execute handler.
159→      // Use resolved path so keys match execute's resolved fileForExec.
160→      const key = `${path.resolve(request.file)}:${request.function}`;
161→      instrumentedSources.set(key, result.instrumentedSource);
162→      lastAnalyzedFile = path.resolve(request.file);
163→
164→      return {
165→        response: {
166→          protocol_version: PROTOCOL_VERSION,
167→          id: request.id,
168→          status: "instrument",
169→          instrumented: true,
170→          output_file: null,
171→          instrumentable_line_count: result.instrumentableLineCount,
172→        },
173→        shutdown: false,
174→      };
175→    }
176→
177→    case "execute": {
178→      const funcRef = request.function;
179→      const fileForExec = resolveFileForExecute(funcRef);
180→
181→      if (!fileForExec) {
182→        return {
183→          response: errorResponse(
184→            request.id,
185→            "function_not_found",
186→            `Cannot resolve file for function: ${funcRef}. Use file:function format.`,
187→          ),
188→          shutdown: false,
189→        };
190→      }
191→
192→      try {
193→        // Check if we have instrumented source for this function
194→        const funcName = funcRef.includes(":") ? funcRef.split(":").pop()! : funcRef;
195→        const instrumentKey = `${fileForExec}:${funcName}`;
196→        const instrumentedSource = instrumentedSources.get(instrumentKey);
197→
198→        let rawResult;
199→        if (instrumentedSource) {
200→          rawResult = await executeInstrumented(instrumentedSource, funcName, request.inputs, request.mocks ?? [], fileForExec);
201→        } else {
202→          rawResult = await executeFunction(fileForExec, funcRef, request.inputs);
203→        }
204→
205→        return {
206→          response: buildExecuteResponse(request.id, PROTOCOL_VERSION, rawResult),
207→          shutdown: false,
208→        };
209→      } catch (e: unknown) {
210→        const msg = e instanceof Error ? e.message : String(e);
211→        return {
212→          response: errorResponse(request.id, "internal_error", `Execute failed: ${msg}`),
213→          shutdown: false,
214→        };
215→      }
216→    }
217→
218→    case "setup": {
219→      if (!fs.existsSync(request.file)) {
220→        return {
221→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
222→          shutdown: false,
223→        };
224→      }
225→
226→      try {
227→        let setupModule = loadedSetupModules.get(request.file);
228→        if (!setupModule) {
229→          setupModule = loadSetupModule(request.file);
230→          loadedSetupModules.set(request.file, setupModule);
231→        }
232→
233→        const setupContext = await runSetup(
234→          setupModule, request.scope, request.level, request.parent_context,
235→        );
236→        const ctxKey = setupContextKey(request.level, request.scope);
237→        setupContexts.set(ctxKey, { module: setupModule, context: setupContext });
238→
239→        return {
240→          response: {
241→            protocol_version: PROTOCOL_VERSION,
242→            id: request.id,
243→            status: "setup",
244→            setup_context: setupContext,
245→          },
246→          shutdown: false,
247→        };
248→      } catch (e: unknown) {
249→        const msg = e instanceof Error ? e.message : String(e);
250→        return {
251→          response: errorResponse(request.id, "internal_error", `Setup failed: ${msg}`),
252→          shutdown: false,
253→        };
254→      }
255→    }
256→
257→    case "teardown": {
258→      try {
259→        const ctxKey = setupContextKey(request.level, request.scope);
260→        const stored = setupContexts.get(ctxKey);
261→        if (!stored) {
262→          return {
263→            response: errorResponse(
264→              request.id,
265→              "internal_error",
266→              `No setup context found for ${request.level}:${request.scope}. Call setup first.`,
267→            ),
268→            shutdown: false,
269→          };
270→        }
271→
272→        await runTeardown(stored.module, request.scope, stored.context);
273→        setupContexts.delete(ctxKey);
274→        instrumentedSources.clear();
275→        clearModuleCache();
276→
277→        return {
278→          response: {
279→            protocol_version: PROTOCOL_VERSION,
280→            id: request.id,
281→            status: "teardown_ack",
282→          },
283→          shutdown: false,
284→        };
285→      } catch (e: unknown) {
286→        const msg = e instanceof Error ? e.message : String(e);
287→        return {
288→          response: errorResponse(request.id, "internal_error", `Teardown failed: ${msg}`),
289→          shutdown: false,
290→        };
291→      }
292→    }
293→
294→    case "generate": {
295→      if (!fs.existsSync(request.file)) {
296→        return {
297→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
298→          shutdown: false,
299→        };
300→      }
301→
302→      try {
