445→/**
446→ * Clear stored instrumented sources and setup state. Useful for testing.
447→ */
448→export function clearInstrumentedSources(): void {
449→  instrumentedSources.clear();
450→  loadedSetupModules.clear();
451→  setupContexts.clear();
452→}
